using namespace std;
inline ll read()
{
	ll x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(ll x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
ll n,p,b,a[100005],num;
ll qpow(ll x,ll b)
{
    ll a=1;
    while(b){
        if(b&1)a=a*x%p;
        b>>=1;
        x=x*x%p;
    }
    return a;
}
int main(void)
{
    n=read(),b=read(),p=read();
    if(b==0)
    {
        printf("0");
        return 0;
    }
    for(int i=1;i<=n;++i)a[i]=read(),num=max(a[i],num);
    num<<=1;
    write(qpow(num+233,b));
    return false;
}
